function evaluateFeature(user, flag, context){
  const bucket = hash(user.id + flag.name) % 100;
  const inSegment = (flag.segments && flag.segments.length) ? flag.segments.includes(user.segment) : true;
  const regionOK = flag.regionOverride ? user.region === flag.regionOverride : true;
  return (bucket < flag.rolloutPct) && inSegment && regionOK;
}
```

