// Simple rate limiter example (token bucket)
function createRateLimiter(tokensPerWindow, windowMs) {
  let tokens = tokensPerWindow; let t0 = Date.now();
  return function allow() {
    const now = Date.now();
    const elapsed = now - t0;
    if (elapsed > windowMs) { t0 = now; tokens = tokensPerWindow; }
    if (tokens > 0) { tokens--; return true; }
    return false;
  };
}
```

