## Code Example

```javascript
// Core limiter (simplified)
const limiter = new Map();

function allowRequest(key, now = Date.now()) {
  const windowMs = 60000;
  const limit = 60;
  const timestamps = limiter.get(key) || [];
  while (timestamps.length && timestamps[0] <= now - windowMs) timestamps.shift();
  if (timestamps.length < limit) {
    timestamps.push(now);
    limiter.set(key, timestamps);
    return true;
  }
  return false;
}
```

