const buckets = new Map();

function limit(req, res, next){
  const key = req.headers['x-api-key'];
  if(!key) return res.status(400).send('API key required');
  const now = Date.now();
  const arr = buckets.get(key) || [];
  // prune
  while (arr.length && now - arr[0] > 10 * 60 * 1000) arr.shift();
  if (arr.length >= 100) return res.status(429).send('Too many requests');
  arr.push(now);
  buckets.set(key, arr);
  next();
}
```

